            to_remove = set()
            for tbp in PROVIDER_ORDER:
                # Avoid infinite recursion.
                if isinstance(tbp, DirectProvider):
                    continue
                if not tbp.get_identifiers(ed_or_solr):
                    continue
                for acq in tbp.get_acquisitions(ed_or_solr):
