class EbookAccess(OrderedEnum):
    # Keep in sync with solr/conf/enumsConfig.xml !
    NO_EBOOK = 0
    UNCLASSIFIED = 1
    PRINTDISABLED = 2
    BORROWABLE = 3
    PUBLIC = 4

